def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 4):
                penalty += (ratio ** (3 * k)) / (k * 2)
            priorities[i] = ratio ** 3 + penalty
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 6):
                sign = -1 if j % 2 == 0 else 1
                term = sign * (ratio ** j) / j
                score += term
            multiplier = 15 if ratio < 0.3 else 10 if ratio < 0.6 else 5
            priorities[i] = abs(score) * multiplier
            if ratio > 0.8:
                extra = 0
                for m in range(1, 4):
                    extra += (ratio ** m) / (m + 1)
                priorities[i] += extra
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
